class Solution:
    def findMaximumXOR(self, nums: List[int]) -> int:
        root = {}
        ans = 0
        for x in nums:
            node = root
            for i in range(31, -1, -1):
                b = (x >> i) & 1
                node = node.setdefault(b, {})
        for x in nums:
            node, val = root, 0
            for i in range(31, -1, -1):
                b = (x >> i) & 1
                want = 1 - b
                if want in node:
                    val |= 1 << i
                    node = node[want]
                else:
                    node = node[b]
            ans = max(ans, val)
        return ans

