int findMaximumXOR(int* nums, int n) {
    int ans=0;
    for(int i=0;i<n;i++) for(int j=i+1;j<n;j++){
        int v=nums[i]^nums[j]; if(v>ans) ans=v;
    }
    return ans;
}
